import { useState, useEffect, useRef, useCallback } from 'react';
import ChatSidebar, { SidebarToggle } from './components/ChatSidebar';
import ChatThread from './components/ChatThread';
import ChatInput from './components/ChatInput';
import { checkHealth, analyzeTranscript } from './api';

const uid = () => crypto.randomUUID?.() || String(Date.now()) + Math.random().toString(36).slice(2);

const makeTitle = (text) => {
  const t = text.trim();
  return t.length > 40 ? t.slice(0, 40) + '...' : t;
};

export default function App() {
  const [conversations, setConversations] = useState(() => {
    try { return JSON.parse(localStorage.getItem('stockai-conversations') || '[]'); }
    catch { return []; }
  });
  const [activeId, setActiveId] = useState(() => {
    try { return localStorage.getItem('stockai-active') || null; }
    catch { return null; }
  });
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [health, setHealth] = useState(null);
  const [loading, setLoading] = useState(false);
  const [stage, setStage] = useState(-1);
  const timerRef = useRef(null);

  // Persist
  useEffect(() => {
    localStorage.setItem('stockai-conversations', JSON.stringify(conversations));
  }, [conversations]);
  useEffect(() => {
    if (activeId) localStorage.setItem('stockai-active', activeId);
  }, [activeId]);

  // Health check
  useEffect(() => {
    checkHealth().then(setHealth).catch(() => setHealth({ anthropic: false, openai: false }));
  }, []);

  // Active conversation
  const activeConv = conversations.find(c => c.id === activeId);
  const messages = activeConv?.messages || [];

  // New chat
  const newChat = useCallback(() => {
    const id = uid();
    setConversations(prev => [
      { id, title: 'New conversation', createdAt: new Date().toISOString(), messages: [] },
      ...prev,
    ]);
    setActiveId(id);
  }, []);

  // Send message (text or transcribed audio)
  const sendMessage = useCallback(async (text, source = 'text') => {
    if (loading || !text.trim()) return;

    let convId = activeId;

    // Create new conversation if none active or current has messages
    if (!convId || (activeConv && activeConv.messages.length > 0)) {
      convId = uid();
      const newConv = { id: convId, title: makeTitle(text), createdAt: new Date().toISOString(), messages: [] };
      setConversations(prev => [newConv, ...prev]);
      setActiveId(convId);
    }

    const userMsg = {
      id: uid(), role: 'user', type: source,
      content: text.trim(), timestamp: new Date().toISOString(),
    };
    const assistantMsgId = uid();
    const assistantMsg = {
      id: assistantMsgId, role: 'assistant', type: 'analysis',
      content: '', data: null, error: null, loading: true,
      timestamp: new Date().toISOString(),
    };

    // Add both messages
    setConversations(prev => prev.map(c =>
      c.id === convId
        ? {
            ...c,
            title: c.messages.length === 0 ? makeTitle(text) : c.title,
            messages: [...c.messages, userMsg, assistantMsg],
          }
        : c
    ));

    // Start pipeline
    setLoading(true);
    setStage(0);
    let s = 0;
    timerRef.current = setInterval(() => {
      s++;
      if (s < 4) setStage(s);
      else clearInterval(timerRef.current);
    }, 900);

    try {
      const data = await analyzeTranscript(text.trim());
      clearInterval(timerRef.current);
      setStage(4);
      await new Promise(r => setTimeout(r, 350));

      // Update assistant message with result
      setConversations(prev => prev.map(c =>
        c.id === convId
          ? {
              ...c,
              title: data.ticker ? `${data.ticker} — ${makeTitle(text)}` : c.title,
              messages: c.messages.map(m =>
                m.id === assistantMsgId ? { ...m, loading: false, data } : m
              ),
            }
          : c
      ));
    } catch (e) {
      clearInterval(timerRef.current);
      setConversations(prev => prev.map(c =>
        c.id === convId
          ? {
              ...c,
              messages: c.messages.map(m =>
                m.id === assistantMsgId ? { ...m, loading: false, error: e.message } : m
              ),
            }
          : c
      ));
    } finally {
      setLoading(false);
      setStage(-1);
    }
  }, [activeId, activeConv, loading]);

  // Delete conversation
  const deleteConversation = useCallback((id) => {
    setConversations(prev => prev.filter(c => c.id !== id));
    if (activeId === id) setActiveId(null);
  }, [activeId]);

  // Select conversation
  const selectConversation = useCallback((id) => {
    setActiveId(id);
  }, []);

  return (
    <div style={{ height: '100vh', display: 'flex', background: 'var(--chat-bg)' }}>

      {/* Sidebar */}
      <ChatSidebar
        conversations={conversations}
        activeId={activeId}
        onSelect={selectConversation}
        onNewChat={newChat}
        onDelete={deleteConversation}
        collapsed={!sidebarOpen}
        onToggle={() => setSidebarOpen(p => !p)}
        health={health}
      />

      {/* Main area */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0 }}>

        {/* Top bar (collapsed sidebar toggle + title) */}
        <div style={{
          height: 48, display: 'flex', alignItems: 'center',
          padding: '0 16px', gap: 12, flexShrink: 0,
        }}>
          {!sidebarOpen && <SidebarToggle onClick={() => setSidebarOpen(true)} />}
          {!sidebarOpen && (
            <span style={{ fontSize: 14, fontWeight: 500, color: 'var(--ink-2)' }}>
              Stock AI
            </span>
          )}
        </div>

        {/* Chat thread */}
        <ChatThread
          messages={messages}
          stage={stage}
          onSampleClick={(text) => sendMessage(text, 'text')}
        />

        {/* Input */}
        <ChatInput
          onSend={(text, source) => sendMessage(text, source)}
          onSendAudio={(text, source) => sendMessage(text, source)}
          loading={loading}
        />
      </div>
    </div>
  );
}
